       // If all indices are the same, just compare the base pointers.
       Type *BaseType = GEPLHS->getOperand(0)->getType();
-      if (IndicesTheSame && CmpInst::makeCmpResultType(BaseType) == I.getType())
+      if (IndicesTheSame && CmpInst::makeCmpResultType(BaseType) == I.getType()) {
+        // If the indices are the same, we can compare the base pointers,
+        // but only if the GEPs don't wrap in a way that would change the
+        // comparison result.
+        // For equality, this is always safe.
+        // For signed relations, we need both GEPs to be `nusw`.
+        // For unsigned relations, we need both GEPs to be `nuw`.
+        if (I.isSigned()) {
+          if (!GEPLHS->hasNoSignedWrap() || !GEPRHS->hasNoSignedWrap())
+            return nullptr;
+        } else if (I.isUnsigned()) {
+          if (!GEPLHS->hasNoUnsignedWrap() || !GEPRHS->hasNoUnsignedWrap())
+            return nullptr;
+        }
         return new ICmpInst(Cond, GEPLHS->getOperand(0), GEPRHS->getOperand(0));
+      }

